const detectRecursion = (items: n8n.WorkflowExecuteAdditionalData[]) => {
  const nodeIds = new Set<string>();
  const loops: string[] = [];

  for (const item of items) {
    const workflowData = item.workflow.data.resultData.runData;
    for (const [nodeName, executions] of Object.entries(workflowData)) {
      if (nodeIds.has(nodeName)) {
        loops.push(`Recursive loop detected at node: ${nodeName}`);
      } else {
        nodeIds.add(nodeName);
      }
    }
  }

  return {
    hasRecursion: loops.length > 0,
    loopCount: loops.length,
    details: loops
  };
};

const scanCredentials = (jsonData: any): string[] => {
  const secrets: string[] = [];
  const patterns = [
    /(?i)(api[_-]?key|token|secret|password)[\s:=]+['"]?[a-zA-Z0-9]{20,}/g,
    /(?:ak|sk)[a-z0-9]{64}/gi,
    /xoxb-[0-9]{12}-[a-zA-Z0-9-_]{32}/gi
  ];

  const scanObject = (obj: any) => {
    if (typeof obj === 'string') {
      patterns.forEach(pattern => {
        const matches = obj.match(pattern);
        if (matches) secrets.push(...matches);
      });
    } else if (obj && typeof obj === 'object') {
      Object.values(obj).forEach(scanObject);
    }
  };

  scanObject(jsonData);
  return [...new Set(secrets)];
};

const checkMemoryStaleness = (memoryItems: n8n.INodeExecutionData[][]) => {
  const now = Date.now();
  const staleItems: any[] = [];
  const MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

  for (const item of memoryItems.flat()) {
    const timestamp = item.json.timestamp || item.json.createdAt;
    if (timestamp && (now - new Date(timestamp).getTime()) > MAX_AGE_MS) {
      staleItems.push({
        messageId: item.json.messageId,
        age: Math.floor((now - new Date(timestamp).getTime()) / (1000 * 60 * 60)),
        content: item.json.content?.substring(0, 100)
      });
    }
  }

  return {
    isStale: staleItems.length > 0,
    staleCount: staleItems.length,
    oldestHours: Math.max(...staleItems.map(i => i.age))
  };
};

