const addRecursionGuard = ($input: any[], $workflow: n8n.Workflow) => {
  const executionContext = $workflow.context.get('execution');
  const callCount = executionContext?.callCount || 0;

  if (callCount > 5) {
    throw new Error('Max recursion depth exceeded');
  }

  executionContext.callCount = callCount + 1;

  return $input.map(item => ({
    json: {
      ...item.json,
      recursionGuard: {
        callCount,
        maxDepth: 5,
        safeToProceed: callCount <= 5
      }
    }
  }));
};

