const validateAgentOutput = (items: n8n.INodeExecutionData[]) => {
  const expectedSchema = {
    action: 'string',
    parameters: {
      url?: 'string',
      method?: 'string',
      headers: { type: 'object' }
    }
  };

  return items.map(item => {
    try {
      const data = item.json;
      // Validate required fields
      if (!data.action || typeof data.action !== 'string') {
        throw new Error('Missing or invalid action field');
      }

      // Sanitize parameters
      const safeParams = {
        ...data.parameters,
        headers: data.parameters?.headers || {}
      };

      return {
        json: {
          validated: true,
          action: data.action,
          parameters: safeParams,
          original: data
        }
      };
    } catch (error) {
      return {
        json: {
          validated: false,
          error: error.message,
          original: item.json
        }
      };
    }
  });
};

