const filterFreshMemory = (memoryItems: any[]) => {
  const now = Date.now();
  const MAX_AGE_HOURS = 24;
  const FRESH_THRESHOLD = MAX_AGE_HOURS * 60 * 60 * 1000;

  const freshMemory = memoryItems.filter(item => {
    const timestamp = new Date(item.timestamp || item.createdAt).getTime();
    return (now - timestamp) < FRESH_THRESHOLD;
  }).slice(-10); // Keep last 10 fresh messages

  return [{
    json: {
      context: freshMemory,
      filteredCount: memoryItems.length - freshMemory.length,
      totalFresh: freshMemory.length,
      cutoffAgeHours: MAX_AGE_HOURS
    }
  }];
};

