import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

// n8n Code Node after AI Agent
export default defineN8nCodeNode({
  async process(inputData, workflow) {
    const aiOutput = inputData[0].json;

    // Capture agent execution for drift monitoring
    const trace = await vex.agent.trace({
      workflowId: workflow.id!,
      nodeName: workflow.node?.name,
      input: aiOutput,
      metadata: {
        n8nNodeType: workflow.node?.type,
        executionId: workflow.execution?.id
      }
    });

    // Auto-detect common drift patterns
    const issues = await vex.agent.detectDrift({
      traceId: trace.id,
      patterns: ['recursion', 'credential_leak', 'stale_context'],
      framework: 'n8n'
    });

    if (issues.length > 0) {
      await vex.agent.alert({
        traceId: trace.id,
        issues,
        severity: 'high',
        remediation: vex.suggestedFixes(issues)
      });
    }

    return {
      json: {
        ...aiOutput,
        vexTraceId: trace.id,
        driftScore: trace.driftScore,
        safeToProceed: issues.length === 0
      }
    };
  }
});
